selector_to_html = {"a[href=\"#nwbarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">NWBArray<a class=\"headerlink\" href=\"#nwbarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading NWB (Neurodata Without Borders) files</p>", "a[href=\"#decision-tree-what-will-imread-return\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Decision Tree: What Will imread() Return?<a class=\"headerlink\" href=\"#decision-tree-what-will-imread-return\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#d-volumetric-data\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">4D Volumetric Data<a class=\"headerlink\" href=\"#d-volumetric-data\" title=\"Link to this heading\">#</a></h4><p><strong>Key Features:</strong></p>", "a[href=\"#common-properties-across-all-array-types\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Common Properties Across All Array Types<a class=\"headerlink\" href=\"#common-properties-across-all-array-types\" title=\"Link to this heading\">#</a></h2><p>All lazy array types provide these standard properties:</p>", "a[href=\"#binarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">BinArray<a class=\"headerlink\" href=\"#binarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Explicitly reading a <code class=\"docutils literal notranslate\"><span class=\"pre\">.bin</span></code> file path</p>", "a[href=\"#lazy-array-types\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Lazy Array Types<a class=\"headerlink\" href=\"#lazy-array-types\" title=\"Link to this heading\">#</a></h1><p>Understanding what <code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code> returns and when to use each array type.</p>", "a[href=\"#suite2parray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Suite2pArray<a class=\"headerlink\" href=\"#suite2parray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading a directory containing <code class=\"docutils literal notranslate\"><span class=\"pre\">ops.npy</span></code>, or <code class=\"docutils literal notranslate\"><span class=\"pre\">ops.npy</span></code> directly</p>", "a[href=\"#api-reference\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">API Reference<a class=\"headerlink\" href=\"#api-reference\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#zarrarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">ZarrArray<a class=\"headerlink\" href=\"#zarrarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading Zarr stores (<code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code> directories)</p>", "a[href=\"#mborawarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">MboRawArray<a class=\"headerlink\" href=\"#mborawarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading raw ScanImage TIFF files with multi-ROI metadata</p>", "a[href=\"#tiffarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">TiffArray<a class=\"headerlink\" href=\"#tiffarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading processed TIFF file(s) without ScanImage metadata</p>", "a[href=\"#from-in-memory-numpy-arrays\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">From In-Memory Numpy Arrays<a class=\"headerlink\" href=\"#from-in-memory-numpy-arrays\" title=\"Link to this heading\">#</a></h4>", "a[href=\"#suite2pvolumearray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Suite2pVolumeArray<a class=\"headerlink\" href=\"#suite2pvolumearray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Directory contains multiple <code class=\"docutils literal notranslate\"><span class=\"pre\">planeXX/</span></code> subdirectories with <code class=\"docutils literal notranslate\"><span class=\"pre\">ops.npy</span></code></p>", "a[href=\"#tiffvolumearray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">TiffVolumeArray<a class=\"headerlink\" href=\"#tiffvolumearray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Directory contains files matching <code class=\"docutils literal notranslate\"><span class=\"pre\">planeXX.tiff</span></code> pattern</p>", "a[href=\"#overview\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Overview<a class=\"headerlink\" href=\"#overview\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">mbo_utilities.imread()</span></code> is a smart file reader that automatically detects the file type and returns the appropriate lazy array class. All array types provide:</p>", "a[href=\"#from-npy-files-memory-mapped\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">From .npy Files (Memory-Mapped)<a class=\"headerlink\" href=\"#from-npy-files-memory-mapped\" title=\"Link to this heading\">#</a></h4>", "a[href=\"#array-type-details\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Array Type Details<a class=\"headerlink\" href=\"#array-type-details\" title=\"Link to this heading\">#</a></h2><h3>MboRawArray<a class=\"headerlink\" href=\"#mborawarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading raw ScanImage TIFF files with multi-ROI metadata</p>", "a[href=\"#numpyarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">NumpyArray<a class=\"headerlink\" href=\"#numpyarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading <code class=\"docutils literal notranslate\"><span class=\"pre\">.npy</span></code> files OR passing an in-memory numpy array to <code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code></p><p>This is the most versatile array type - it wraps any numpy array and provides full <code class=\"docutils literal notranslate\"><span class=\"pre\">imwrite()</span></code> support.</p>", "a[href=\"#mbotiffarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">MBOTiffArray<a class=\"headerlink\" href=\"#mbotiffarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading TIFFs with MBO-specific metadata (uses Dask backend)</p>", "a[href=\"#quick-reference\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Quick Reference<a class=\"headerlink\" href=\"#quick-reference\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#isoviewarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">IsoviewArray<a class=\"headerlink\" href=\"#isoviewarray\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Manually instantiated for isoview lightsheet microscopy data</p>", "a[href=\"#h5array\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">H5Array<a class=\"headerlink\" href=\"#h5array\" title=\"Link to this heading\">#</a></h3><p><strong>Returned when:</strong> Reading HDF5 files (<code class=\"docutils literal notranslate\"><span class=\"pre\">.h5</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">.hdf5</span></code>)</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
